SELECT d.id AS id, u.uuid::text AS author_uuid, u.nickname AS author_nickname, u.profile_image_url AS author_profile_image_url, d.mood_emoji AS mood_emoji, d.ai_title AS ai_title, left(d.content_text, 120) AS preview, d.written_date AS written_date, d.visibility AS visibility, d.primary_emotion AS primary_emotion, d.background_color AS background_color, d.accent_color AS accent_color, d.reaction_count AS reaction_count, EXISTS(SELECT 1 FROM diary_reactions r WHERE r.diary_id = d.id AND r.user_id = #{viewerId}) AS reacted_by_me FROM diaries d JOIN users u ON u.id = d.user_id WHERE d.deleted_at IS NULL AND d.analysis_status = 'DONE' AND ( d.user_id = #{viewerId} OR d.visibility = 'PUBLIC' OR (d.visibility = 'FRIENDS' AND d.user_id IN ()) ) AND
AND d.id < #{cursor}
ORDER BY d.id DESC LIMIT #{limit}
